// === Parse JSON Entrada ===
// Recebe o texto colado no campo "Dados JSON" do formulario e extrai os campos.
const first = $input.first().json || {};
const raw = first["Dados JSON"] || first.dadosJson || first.data || first.json || "";

function cleanAndParse(input) {
  if (input == null) return {};
  if (typeof input === 'object') return input;
  let s = String(input).trim();
  // remove cercas markdown ```json ... ```
  s = s.replace(/```json/gi, '').replace(/```/g, '').trim();
  // localiza o primeiro { ou [
  const firstObj = s.indexOf('{');
  const firstArr = s.indexOf('[');
  let start = -1;
  if (firstArr !== -1 && (firstArr < firstObj || firstObj === -1)) {
    start = firstArr;
  } else {
    start = firstObj;
  }
  if (start > 0) s = s.slice(start);
  // localiza o ultimo } ou ]
  const lastObj = s.lastIndexOf('}');
  const lastArr = s.lastIndexOf(']');
  const end = Math.max(lastObj, lastArr);
  if (end !== -1) s = s.slice(0, end + 1);
  try {
    return JSON.parse(s);
  } catch (e) {
    // tenta remover virgulas pendentes
    try {
      return JSON.parse(s.replace(/,\s*([}\]])/g, '$1'));
    } catch (e2) {
      throw new Error('Nao foi possivel parsear o JSON de entrada: ' + e2.message);
    }
  }
}

let parsed = cleanAndParse(raw);
if (Array.isArray(parsed)) parsed = parsed[0] || {};

const jtbd = parsed.jtbd || {};
const pesquisa = parsed.pesquisa || {};
const estrategia = parsed.estrategia || {};

let numClips = parseInt(parsed.numClips, 10);
if (isNaN(numClips) || numClips < 14) numClips = 14;

let duracao = parseInt(parsed.duracaoClip, 10);
if (isNaN(duracao) || duracao <= 0) duracao = 4;

const servico = parsed.servico || parsed.keyword || 'Servico DJE';
const metaDesc = parsed.observacoes || (estrategia && estrategia.puv) || '';

return [{
  json: {
    articleTitle: servico,
    servico: servico,
    keyword: parsed.keyword || '',
    plataforma: parsed.plataforma || 'Facebook Ads',
    metaDescription: metaDesc,
    observacoes: parsed.observacoes || '',
    numberOfClips: numClips,
    duration: duracao,
    persona: parsed.persona || '',
    empresa: parsed.empresa || 'DJE Construcao e Reformas',
    jtbd: jtbd,
    pesquisa: pesquisa,
    estrategia: estrategia
  }
}];

