// === Parser Roteiro ===
// Extrai o roteiro do Agente Diretor cobrindo TODAS as formas de saida do node OpenAI,
// inclusive a Responses API nova (output[0].content[0].text com o JSON dentro).
const item = $input.first().json || {};

function extractJson(s) {
  s = String(s).replace(/```json/gi, '').replace(/```/g, '').trim();
  const fo = s.indexOf('{');
  const fa = s.indexOf('[');
  let start = -1;
  if (fa !== -1 && (fa < fo || fo === -1)) start = fa; else start = fo;
  if (start > 0) s = s.slice(start);
  const lo = s.lastIndexOf('}');
  const la = s.lastIndexOf(']');
  const end = Math.max(lo, la);
  if (end !== -1) s = s.slice(0, end + 1);
  try { return JSON.parse(s); }
  catch (e) {
    try { return JSON.parse(s.replace(/,\s*([}\]])/g, '$1')); }
    catch (e2) { return null; }
  }
}

function looksLikeRoteiro(arr) {
  if (!Array.isArray(arr) || arr.length === 0) return false;
  const c = arr[0];
  if (!c || typeof c !== 'object') return false;
  return ('imagem_prompt' in c) || ('image_prompt' in c) || ('imagemPrompt' in c) ||
         ('prompt' in c) || ('texto_narracao' in c) || ('narracao' in c) ||
         ('narration' in c) || ('fase' in c);
}

function findRoteiro(obj) {
  if (!obj || typeof obj !== 'object') return null;
  if (Array.isArray(obj)) return looksLikeRoteiro(obj) ? obj : null;
  if (Array.isArray(obj.roteiro_video) && obj.roteiro_video.length) return obj.roteiro_video;
  for (const k of Object.keys(obj)) {
    if (Array.isArray(obj[k]) && looksLikeRoteiro(obj[k])) return obj[k];
  }
  return null;
}

function deepFind(node, depth) {
  if (node == null || depth > 8) return null;
  if (typeof node === 'string') {
    const parsed = extractJson(node);
    if (parsed) {
      const r = findRoteiro(parsed);
      if (r) return r;
      return deepFind(parsed, depth + 1);
    }
    return null;
  }
  if (typeof node === 'object') {
    const r = findRoteiro(node);
    if (r) return r;
    const vals = Array.isArray(node) ? node : Object.keys(node).map(function (k) { return node[k]; });
    for (const v of vals) {
      const d = deepFind(v, depth + 1);
      if (d) return d;
    }
  }
  return null;
}

let roteiro = deepFind(item, 0);

if (!roteiro) {
  const keys = Object.keys(item || {});
  let sample = '';
  try { sample = JSON.stringify(item); } catch (e) { sample = String(item); }
  if (sample && sample.length > 600) sample = sample.slice(0, 600);
  throw new Error('Parser Roteiro: nao encontrei roteiro_video. Keys: ' + JSON.stringify(keys) + '. Amostra: ' + sample);
}

const ctx = $('Edit Fields1').first().json || {};
roteiro = roteiro.map(function (c, i) {
  return {
    clip: c.clip || (i + 1),
    fase: c.fase || '',
    imagem_prompt: c.imagem_prompt || c.image_prompt || c.imagemPrompt || c.prompt || '',
    texto_narracao: c.texto_narracao || c.narracao || c.narration || '',
    articleTitle: ctx.articleTitle || '',
    duration: ctx.duration || 4
  };
});

return [{ json: { roteiro_video: roteiro } }];

// === Parse Generated Prompts ===
// Gera taskUUID (UUIDv4) e final_prompt por clip; define resolucao vertical 1080x1920.
// GUARDA: bloqueia clips com imagem_prompt vazio (evita positivePrompt vazio na RunWare).
function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}
const items = $input.all();
const out = [];
for (let idx = 0; idx < items.length; idx++) {
  const it = items[idx];
  const j = it.json || {};
  const clipNum = j.clip || (idx + 1);
  const final_prompt = (j.imagem_prompt || j.final_prompt || '').toString().trim();
  if (final_prompt.length < 2) {
    throw new Error('Parse Generated Prompts: imagem_prompt vazio no clip ' + clipNum + '. Keys recebidas: ' + JSON.stringify(Object.keys(j)));
  }
  out.push({
    json: {
      ...j,
      final_prompt: final_prompt,
      taskUUID: uuidv4(),
      width: 1536,
      height: 2752,
      texto_narracao: j.texto_narracao || '',
      clip: j.clip
    }
  });
}
return out;

// === Increment Retry Counter ===
// retry_count baseado em $runIndex (incrementa a cada volta do loop),
// pois o json e' sobrescrito pela resposta HTTP do Check Result.
const j = $input.first().json || {};
const rc = ($runIndex || 0) + 1;
return [{ json: Object.assign({}, j, { retry_count: rc }) }];

// === Preparar Arquivos (Run Once for Each Item) ===
// Processa UM clip por execucao -> nunca estoura o limite de 300s do task runner.
// Versao paste-safe: sem sequencias \n em strings (usa NL = fromCharCode(10)).
const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');
const TMP = '/tmp';
const NL = String.fromCharCode(10);

function resolverCaminho(bin) {
  if (!bin) return null;
  const id = bin.id ? String(bin.id).split(':').pop() : null;
  const candidatos = [];
  if (id) {
    candidatos.push(
      path.join('/home/node/.n8n/binaryData', id),
      path.join('/home/node/.n8n/binaryData', id + '.bin'),
      path.join('/data/.n8n/binaryData', id),
      path.join('/tmp', id)
    );
  }
  for (const c of candidatos) { try { if (fs.existsSync(c)) return c; } catch (e) {} }
  return null;
}

async function getBuf(prop, bin) {
  try {
    const b = await this.helpers.getBinaryDataBuffer(0, prop);
    if (b && b.length) return b;
  } catch (e) {}
  const p = resolverCaminho(bin && bin[prop]);
  if (p) { try { return fs.readFileSync(p); } catch (e) {} }
  return null;
}

function escapeDraw(t) {
  return String(t || '')
    .split('\\').join('\\\\')
    .split(':').join('\\:')
    .split("'").join(String.fromCharCode(8217))
    .split('%').join('\\%')
    .split(',').join('\\,');
}
function wrapTexto(t, maxChars) {
  const palavras = String(t || '').split(/\s+/);
  const linhas = [];
  let atual = '';
  for (const p of palavras) {
    if ((atual + ' ' + p).trim().length > maxChars) {
      if (atual) linhas.push(atual.trim());
      atual = p;
    } else { atual = (atual + ' ' + p).trim(); }
  }
  if (atual) linhas.push(atual.trim());
  return linhas.join(NL);
}
function escapeAss(t) {
  return String(t == null ? '' : t)
    .split('\\').join(' ')
    .split('{').join('(')
    .split('}').join(')')
    .replace(/\s+/g, ' ')
    .trim();
}
function assTime(t) {
  if (!(t > 0)) t = 0;
  let cs = Math.round(t * 100);
  const h = Math.floor(cs / 360000); cs -= h * 360000;
  const m = Math.floor(cs / 6000); cs -= m * 6000;
  const s = Math.floor(cs / 100); cs -= s * 100;
  const pad = (n, l) => String(n).padStart(l, '0');
  return h + ':' + pad(m, 2) + ':' + pad(s, 2) + '.' + pad(cs, 2);
}

const FONT = (function () {
  const fontes = [
    '/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf',
    '/usr/share/fonts/dejavu/DejaVuSans-Bold.ttf',
    '/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf'
  ];
  for (const f of fontes) { try { if (fs.existsSync(f)) return f; } catch (e) {} }
  return null;
})();
const FONTS_DIR = FONT ? path.dirname(FONT) : '';
const ASS_FONT = (FONT && /liberation/i.test(FONT)) ? 'Liberation Sans' : 'DejaVu Sans';

const json = $input.item.json || {};
const bin = $input.item.binary || {};
const clipNum = json.clip || (($itemIndex || 0) + 1);

const audioBuf = await getBuf.call(this, 'data', bin);
const imgBuf = await getBuf.call(this, 'foto', bin);
if (!audioBuf || !imgBuf) {
  return { json: { clip: clipNum, skipped: true, texto_narracao: json.texto_narracao || '', articleTitle: json.articleTitle || '' } };
}

const audioPath = TMP + '/audio_' + clipNum + '.mp3';
const wavPath = TMP + '/audio_' + clipNum + '.wav';
const webpPath = TMP + '/img_' + clipNum + '.webp';
const pngPath = TMP + '/img_' + clipNum + '.png';
const outPath = TMP + '/clip_' + clipNum + '.mp4';
const assPath = TMP + '/cap_' + clipNum + '.ass';

fs.writeFileSync(audioPath, audioBuf);
fs.writeFileSync(webpPath, imgBuf);

execSync('ffmpeg -y -i "' + audioPath + '" -ar 44100 -ac 2 "' + wavPath + '"', { stdio: 'ignore', timeout: 120000 });
execSync('ffmpeg -y -i "' + webpPath + '" -vf "scale=1080:1920:force_original_aspect_ratio=increase,crop=1080:1920" "' + pngPath + '"', { stdio: 'ignore', timeout: 120000 });

let dur = parseFloat(json.duration) || 4;
try {
  const probe = execSync('ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 "' + wavPath + '"', { timeout: 60000 }).toString().trim();
  const d = parseFloat(probe);
  if (!isNaN(d) && d > 0) dur = d;
} catch (e) {}
const duracaoSeg = dur;

const fps = 25;
const frames = Math.ceil(dur * fps);

const zoomIn = (clipNum % 2 === 1);
const zoomExpr = zoomIn ? "min(zoom+0.0012,1.3)" : "if(lte(zoom,1.0),1.3,max(1.0,zoom-0.0012))";
const zoomPart = "zoompan=z='" + zoomExpr + "':d=" + frames + ":s=1080x1920:fps=" + fps;

const narr = String(json.texto_narracao || '').trim();
const words = narr.split(/\s+/).filter(Boolean);
const wordCount = words.length;

let assOk = false;
if (FONT && wordCount > 0) {
  try {
    const slice = duracaoSeg / wordCount;
    const groupSize = 2;
    const dialogues = [];
    const BS = String.fromCharCode(92);
    const tags = '{' + BS + 'fad(60,40)' + BS + 'fscx55' + BS + 'fscy55' + BS + 't(0,120,' + BS + 'fscx100' + BS + 'fscy100)}';
    for (let w = 0; w < wordCount; w += groupSize) {
      const grp = words.slice(w, w + groupSize);
      const startT = w * slice;
      const endIdx = Math.min(w + groupSize, wordCount);
      let endT = endIdx * slice;
      if (endIdx >= wordCount) endT = duracaoSeg;
      const txt = escapeAss(grp.join(' ').toLocaleUpperCase('pt-BR'));
      if (!txt) continue;
      dialogues.push('Dialogue: 0,' + assTime(startT) + ',' + assTime(endT) + ',Cap,,0,0,0,,' + tags + txt);
    }
    const head = [
      '[Script Info]',
      'ScriptType: v4.00+',
      'PlayResX: 1080',
      'PlayResY: 1920',
      'WrapStyle: 2',
      'ScaledBorderAndShadow: yes',
      '',
      '[V4+ Styles]',
      'Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding',
      'Style: Cap,' + ASS_FONT + ',90,&H00FFFFFF,&H000000FF,&H00000000,&H64000000,-1,0,0,0,100,100,0,0,1,6,3,2,80,80,430,1',
      '',
      '[Events]',
      'Format: Layer, Start, End, Style, MarginL, MarginR, MarginV, Effect, Text'
    ];
    const assContent = head.join(NL) + NL + dialogues.join(NL) + NL;
    fs.writeFileSync(assPath, assContent, { encoding: 'utf8' });
    assOk = fs.existsSync(assPath) && fs.statSync(assPath).size > 0;
  } catch (e) { assOk = false; }
}

const renderFFmpeg = function (vfStr) {
  execSync('ffmpeg -y -loop 1 -i "' + pngPath + '" -i "' + wavPath + '" -t ' + dur.toFixed(3) + ' -r ' + fps + ' -vf "' + vfStr + '" -c:v libx264 -preset veryfast -pix_fmt yuv420p -c:a aac -b:a 192k -shortest -movflags +faststart "' + outPath + '"', { stdio: 'ignore', timeout: 240000 });
};

let rendered = false;
if (assOk) {
  try {
    const escAss = assPath.split('\\').join('\\\\').split(':').join('\\:').split("'").join("\\'");
    const escDir = FONTS_DIR.split('\\').join('\\\\').split(':').join('\\:').split("'").join("\\'");
    const dirOpt = FONTS_DIR ? ":fontsdir='" + escDir + "'" : '';
    const vf = zoomPart + ",format=yuv420p,ass='" + escAss + "'" + dirOpt;
    renderFFmpeg(vf);
    rendered = fs.existsSync(outPath) && fs.statSync(outPath).size > 0;
  } catch (e) { rendered = false; }
}

if (!rendered) {
  const texto = escapeDraw(wrapTexto(json.texto_narracao, 26));
  const fontPart = FONT ? "fontfile='" + FONT + "':" : '';
  const drawtext = "drawtext=" + fontPart + "text='" + texto + "':fontcolor=white:fontsize=56:line_spacing=10:box=1:boxcolor=black@0.55:boxborderw=22:borderw=4:bordercolor=black:x=(w-text_w)/2:y=h-h*0.28";
  const vf = zoomPart + "," + drawtext;
  renderFFmpeg(vf);
}

const outBuf = fs.readFileSync(outPath);
return {
  json: { clip: clipNum, texto_narracao: json.texto_narracao || '', duration: dur, articleTitle: json.articleTitle || '' },
  binary: { data: await this.helpers.prepareBinaryData(outBuf, 'clip_' + clipNum + '.mp4', 'video/mp4') }
};

// === Preparar Paths ===
// Concatena todos os clips com transicoes crossfade (xfade/acrossfade),
// sobrepoe a logo DJE e um overlay de CTA, gerando o video final vertical.
// ENHANCEMENT 3: opcionalmente mixa uma musica de fundo em volume baixo sob toda a narracao.
// ASYNC: usa exec promisificado (await) para nao bloquear o event loop do task runner.
const fs = require('fs');
const path = require('path');
const { exec } = require('child_process');
function execAsync(cmd, opts) {
  return new Promise(function (resolve, reject) {
    exec(cmd, opts, function (err, stdout, stderr) {
      if (err) { reject(err); } else { resolve({ stdout: stdout, stderr: stderr }); }
    });
  });
}
const EXEC_OPTS = { timeout: 300000, maxBuffer: 1024 * 1024 * 128 };
const NL = String.fromCharCode(10);
const BS = String.fromCharCode(92);
const TMP = '/tmp';

function resolverCaminho(bin) {
  if (!bin) return null;
  const id = bin.id ? String(bin.id).split(':').pop() : null;
  const candidatos = [];
  if (id) {
    candidatos.push(
      path.join('/home/node/.n8n/binaryData', id),
      path.join('/home/node/.n8n/binaryData', id + '.bin'),
      path.join('/data/.n8n/binaryData', id),
      path.join('/tmp', id)
    );
  }
  for (const c of candidatos) { try { if (fs.existsSync(c)) return c; } catch (e) {} }
  return null;
}

async function getBuf(idx, prop, bin) {
  try {
    const b = await this.helpers.getBinaryDataBuffer(idx, prop);
    if (b && b.length) return b;
  } catch (e) {}
  const p = resolverCaminho(bin && bin[prop]);
  if (p) { try { return fs.readFileSync(p); } catch (e) {} }
  return null;
}

const items = $input.all();
const clipPaths = [];
let articleTitle = 'video_dje';
for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  if (items[i].json && items[i].json.articleTitle) articleTitle = items[i].json.articleTitle;
  const buf = await getBuf.call(this, i, 'data', bin);
  if (!buf) continue;
  const p = `${TMP}/seg_${i}.mp4`;
  fs.writeFileSync(p, buf);
  clipPaths.push(p);
}

if (clipPaths.length === 0) {
  throw new Error('Nenhum clip disponivel para concatenar.');
}

// baixa a logo DJE branca (User-Agent de navegador)
const logoPath = `${TMP}/logo_dje.png`;
try {
  await execAsync(`wget -q --user-agent="Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0 Safari/537.36" -O "${logoPath}" "https://construcao.djereformas.com.br/wp-content/uploads/2026/03/logo-DJE-branco.png"`, { timeout: 120000, maxBuffer: 1024 * 1024 * 16 });
} catch (e) {}
const temLogo = (function () { try { return fs.existsSync(logoPath) && fs.statSync(logoPath).size > 0; } catch (e) { return false; } })();

const FONT = (function () {
  const fontes = [
    '/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf',
    '/usr/share/fonts/dejavu/DejaVuSans-Bold.ttf',
    '/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf'
  ];
  for (const f of fontes) { try { if (fs.existsSync(f)) return f; } catch (e) {} }
  return null;
})();
const fontPart = FONT ? `fontfile='${FONT}':` : '';
const ctaText = 'Orcamento gratis' + BS + ': WhatsApp (11) 5891.6837';
const ctaDraw = `drawtext=${fontPart}text='${ctaText}':fontcolor=white:fontsize=48:box=1:boxcolor=black@0.6:boxborderw=18:x=(w-text_w)/2:y=h*0.06:enable='gte(t,0)'`;

const XF = 0.5; // duracao do crossfade
let finalPath = `${TMP}/final_${Date.now()}.mp4`;

async function probeDur(p) {
  try {
    const r = await execAsync('ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 "' + p + '"', { timeout: 60000, maxBuffer: 1024 * 1024 * 16 });
    const d = parseFloat(String(r.stdout).trim());
    return (!isNaN(d) && d > 0) ? d : 4;
  } catch (e) { return 4; }
}

let sucesso = false;
try {
  const inputs = clipPaths.map(p => `-i "${p}"`).join(' ');
  let filter = '';
  let vlast, alast;

  if (clipPaths.length === 1) {
    vlast = '[0:v]';
    alast = '[0:a]';
  } else {
    const durs = [];
    for (const cp of clipPaths) { durs.push(await probeDur(cp)); }
    vlast = '[0:v]';
    alast = '[0:a]';
    let offset = durs[0] - XF;
    for (let i = 1; i < clipPaths.length; i++) {
      const vout = `[v${i}]`;
      const aout = `[a${i}]`;
      filter += `${vlast}[${i}:v]xfade=transition=fade:duration=${XF}:offset=${offset.toFixed(3)}${vout};`;
      filter += `${alast}[${i}:a]acrossfade=d=${XF}${aout};`;
      vlast = vout;
      alast = aout;
      offset += durs[i] - XF;
    }
  }

  // overlay da logo + CTA
  const logoIdx = clipPaths.length;
  let videoChain = vlast;
  if (temLogo) {
    filter += `[${logoIdx}:v]scale=320:-1[lg];${videoChain}[lg]overlay=W-w-40:H-h-60[vlogo];`;
    videoChain = '[vlogo]';
  }
  filter += `${videoChain}${ctaDraw}[vout]`;

  const logoInput = temLogo ? `-i "${logoPath}"` : '';
  await execAsync(`ffmpeg -y ${inputs} ${logoInput} -filter_complex "${filter}" -map "[vout]" -map "${alast}" -c:v libx264 -preset veryfast -pix_fmt yuv420p -c:a aac -b:a 192k -movflags +faststart "${finalPath}"`, EXEC_OPTS);
  sucesso = fs.existsSync(finalPath);
} catch (e) {
  sucesso = false;
}

// fallback: concat demuxer simples + logo/CTA se o xfade falhar
if (!sucesso) {
  const listPath = `${TMP}/concat_list.txt`;
  fs.writeFileSync(listPath, clipPaths.map(p => `file '${p}'`).join(NL));
  const concatPath = `${TMP}/concat_${Date.now()}.mp4`;
  await execAsync(`ffmpeg -y -f concat -safe 0 -i "${listPath}" -c copy "${concatPath}"`, EXEC_OPTS);
  if (temLogo) {
    await execAsync(`ffmpeg -y -i "${concatPath}" -i "${logoPath}" -filter_complex "[1:v]scale=320:-1[lg];[0:v][lg]overlay=W-w-40:H-h-60[vl];[vl]${ctaDraw}[vout]" -map "[vout]" -map 0:a -c:v libx264 -preset veryfast -pix_fmt yuv420p -c:a aac -movflags +faststart "${finalPath}"`, EXEC_OPTS);
  } else {
    await execAsync(`ffmpeg -y -i "${concatPath}" -vf "${ctaDraw}" -c:v libx264 -preset veryfast -pix_fmt yuv420p -c:a aac -movflags +faststart "${finalPath}"`, EXEC_OPTS);
  }
}

// === ENHANCEMENT 3: musica de fundo opcional (volume baixo sob a narracao) ===
// Le a URL do formulario. Se vazia ou se o download falhar -> mantem o audio atual (fallback gracioso).
let musicaUrl = '';
try {
  const fdata = $('Formulario de Video').first().json || {};
  musicaUrl = String(fdata['Musica de Fundo (URL)'] || '').trim();
} catch (e) { musicaUrl = ''; }

if (musicaUrl) {
  try {
    const musicPath = `${TMP}/bg_music_${Date.now()}.mp3`;
    // baixa com User-Agent de navegador (mesma abordagem do download da logo)
    await execAsync(`wget -q --user-agent="Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0 Safari/537.36" -O "${musicPath}" "${musicaUrl}"`, { timeout: 120000, maxBuffer: 1024 * 1024 * 16 });
    const musicaOk = (function () { try { return fs.existsSync(musicPath) && fs.statSync(musicPath).size > 4096; } catch (e) { return false; } })();
    if (musicaOk) {
      const mixedPath = `${TMP}/final_mix_${Date.now()}.mp4`;
      // -stream_loop -1 faz a musica repetir; volume=0.12 deixa a musica baixa/ambiente;
      // amix duration=first encerra junto com o video; normalize=0 mantem a narracao em volume cheio (dominante);
      // -shortest garante que nao exceda a duracao do video.
      await execAsync(`ffmpeg -y -i "${finalPath}" -stream_loop -1 -i "${musicPath}" -filter_complex "[1:a]volume=0.12[bg];[0:a][bg]amix=inputs=2:duration=first:dropout_transition=2:normalize=0[aout]" -map 0:v -map "[aout]" -c:v libx264 -preset veryfast -pix_fmt yuv420p -c:a aac -b:a 192k -shortest -movflags +faststart "${mixedPath}"`, EXEC_OPTS);
      if (fs.existsSync(mixedPath) && fs.statSync(mixedPath).size > 0) {
        finalPath = mixedPath; // passa a usar a versao com musica
      }
    }
  } catch (e) {
    // qualquer falha no download/mix -> mantem finalPath sem musica (nao quebra o workflow)
  }
}

const finalBuf = fs.readFileSync(finalPath);
const nomeArquivo = `${articleTitle}.mp4`;
return [{
  json: { articleTitle: articleTitle, fileName: nomeArquivo },
  binary: { data: await this.helpers.prepareBinaryData(finalBuf, nomeArquivo, 'video/mp4') }
}];
